mapper.insert:
INSERT INTO chat_session_title (session_id, session_title)
VALUES (#{sessionId}, #{sessionTitle})
ON DUPLICATE KEY UPDATE session_title = #{sessionTitle}

mapper.update:
UPDATE chat_session_title
SET session_title = #{sessionTitle}
WHERE session_id = #{sessionId}

mapper.select:
SELECT session_id, session_title
FROM chat_session_title
WHERE session_id = #{sessionId}
